import{_ as a,o as t,c as r,ag as o}from"./chunks/framework.BYehg5q7.js";const m=JSON.parse('{"title":"Manual Entry","description":"","frontmatter":{},"headers":[],"relativePath":"guide/manual-entry.md","filePath":"guide/manual-entry.md","lastUpdated":1773136324000}'),n={name:"guide/manual-entry.md"};function i(s,e,l,u,d,c){return t(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="manual-entry" tabindex="-1">Manual Entry <a class="header-anchor" href="#manual-entry" aria-label="Permalink to &quot;Manual Entry&quot;">​</a></h1><p>If you have lab results but no PDF — for example, values written on paper, a result emailed as plain text, or numbers from a health device — you can enter them directly into getbased using the manual entry form.</p><h2 id="no-ai-provider-needed" tabindex="-1">No AI Provider Needed <a class="header-anchor" href="#no-ai-provider-needed" aria-label="Permalink to &quot;No AI Provider Needed&quot;">​</a></h2><p>Manual entry does not use AI. You don&#39;t need an API key or any provider configured to use it.</p><h2 id="how-to-use-manual-entry" tabindex="-1">How to Use Manual Entry <a class="header-anchor" href="#how-to-use-manual-entry" aria-label="Permalink to &quot;How to Use Manual Entry&quot;">​</a></h2><ol><li>In the sidebar, click <strong>Manual Entry</strong> (or find it in the navigation menu on mobile)</li><li>Select the <strong>date</strong> of the lab draw</li><li>Browse or search for markers by name or category</li><li>Enter the value for each marker you have results for</li><li>Click <strong>Save</strong></li></ol><p>The results are saved immediately and appear in your charts alongside any PDF-imported data.</p><div class="tip custom-block"><p class="custom-block-title">You don&#39;t need to fill in everything</p><p>Only enter the markers you have results for. Leave the rest blank. getbased uses <code>null</code> for missing values and draws chart lines across gaps automatically.</p></div><h2 id="finding-markers" tabindex="-1">Finding Markers <a class="header-anchor" href="#finding-markers" aria-label="Permalink to &quot;Finding Markers&quot;">​</a></h2><p>The marker list is organized by the same 15 categories used throughout the app (biochemistry, hormones, lipids, etc.). You can scroll through a category or use the search box to find a marker by name.</p><p>If a marker you&#39;re looking for doesn&#39;t appear in the list, you can create it. Click the <strong>+</strong> button next to &quot;Categories&quot; in the sidebar to <a href="./custom-markers.html#creating-custom-markers-manually">create a custom marker</a> — define the name, unit, category, and reference range, then add values to it.</p><h2 id="editing-existing-values" tabindex="-1">Editing Existing Values <a class="header-anchor" href="#editing-existing-values" aria-label="Permalink to &quot;Editing Existing Values&quot;">​</a></h2><p>Click any value in the <strong>detail modal</strong> to edit it inline. Changed values show an <strong>&quot;edited ×&quot;</strong> badge — click the × to revert to the original imported value. Manually added values (no original to revert to) show a <strong>&quot;manual&quot;</strong> badge. You can also delete any value using the delete button.</p><div class="tip custom-block"><p class="custom-block-title">Units</p><p>Enter values in whatever unit system you&#39;re currently using (US or SI). getbased automatically converts to its internal format when saving.</p></div><h2 id="use-cases" tabindex="-1">Use Cases <a class="header-anchor" href="#use-cases" aria-label="Permalink to &quot;Use Cases&quot;">​</a></h2><ul><li>Results from a doctor&#39;s visit where only a printout was provided</li><li>Home test kits (cholesterol monitors, blood glucose meters, etc.)</li><li>Entering a single marker you noticed was missing after a PDF import</li><li>Historical values you&#39;ve tracked in a spreadsheet</li></ul>',16)])])}const g=a(n,[["render",i]]);export{m as __pageData,g as default};
